const items = $input.all();
const form = items[0].json;
const category = form['Product Category'] || form.category || 'Area Rug';
const focus = form['Focus Area'] || form.focus || '';
const targetAudience = form['Target Audience'] || form.targetAudience || '';
const seasonalContext = form['Seasonal Context'] || form.seasonalContext || '';
let p2Content = '';
if (form['P2 Market Analysis Report']) {
  const p2Data = form['P2 Market Analysis Report'];
  if (typeof p2Data === 'string') {
    p2Content = p2Data;
  } else if (p2Data.data) {
    p2Content = Buffer.from(p2Data.data, 'base64').toString('utf8');
  }
}
let p3Content = '';
if (form['P3 Competitor Analysis Report']) {
  const p3Data = form['P3 Competitor Analysis Report'];
  if (typeof p3Data === 'string') {
    p3Content = p3Data;
  } else if (p3Data.data) {
    p3Content = Buffer.from(p3Data.data, 'base64').toString('utf8');
  }
}
const stripHtml = (html) => {
  return html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
};
const p2Text = stripHtml(p2Content).slice(0, 15000);
const p3Text = stripHtml(p3Content).slice(0, 15000);
return [{
  json: {
    category,
    focus,
    targetAudience,
    seasonalContext,
    p2_content: p2Text,
    p3_content: p3Text
  }
}];

